const d = $input.first().json;

const workflowName = d.workflow?.name || 'Unknown Workflow';
const workflowId = d.workflow?.id || '';
const errorMsg = (d.error?.message || 'No error message').substring(0, 1000);
const lastNode = d.lastNodeExecuted || 'Unknown';
const execUrl = d.execution?.url || ('https://therrancecarrothers.app.n8n.cloud/workflow/' + workflowId + '/executions');

const payload = {
  embeds: [{
    title: '🚨 Workflow Error',
    color: 15158332,
    fields: [
      { name: '📋 Workflow', value: workflowName, inline: true },
      { name: '🔴 Failed At', value: lastNode, inline: true },
      { name: '\u200b', value: '\u200b', inline: false },
      { name: '⚠️ Error', value: errorMsg, inline: false },
      { name: '🔗 View', value: '[Open Execution](' + execUrl + ')', inline: false }
    ],
    timestamp: new Date().toISOString(),
    footer: { text: 'Thurnos Prime • Thurr Solutions Ops' }
  }]
};

return [{ json: { payload: JSON.stringify(payload) } }];

const raw = $input.first().json;
const d = raw.body || raw;

const leadName  = d.leadName  || d.lead_name  || d.name  || 'Unknown Lead';
const phone     = d.phone     || d.phoneNumber || d.phone_number || 'Not provided';
const service   = d.service   || d.serviceNeeded || d.service_needed || 'Not specified';
const source    = d.source    || d.leadSource || d.lead_source || 'Unknown';
const decision  = String(d.decision || d.qualified || d.result || '');
const icpScore  = d.icpScore ?? d.icp_score ?? null;

const qualified = ['pass', 'qualif', 'true', '1'].some(k => decision.toLowerCase().includes(k));
const decisionText = qualified ? '✅ PASS — Qualified' : '❌ FAIL — Not Qualified';
const color = qualified ? 5763719 : 15158332;

const fields = [
  { name: '👤 Lead Name',      value: leadName, inline: true },
  { name: '📞 Phone',          value: phone,    inline: true },
  { name: '\u200b',            value: '\u200b', inline: true },
  { name: '🔧 Service Needed', value: service,  inline: true },
  { name: '📍 Source',         value: source,   inline: true },
  { name: '\u200b',            value: '\u200b', inline: true },
  { name: '🎯 Decision',       value: decisionText, inline: false }
];

if (icpScore !== null && icpScore !== '') {
  fields.push({ name: '📊 ICP Score', value: String(icpScore), inline: true });
}

const payload = {
  embeds: [{
    title: '🎯 New Lead — Thurr Solutions',
    color,
    fields,
    timestamp: new Date().toISOString(),
    footer: { text: 'Thurnos Prime • Lead Qualification System' }
  }]
};

return [{ json: { payload: JSON.stringify(payload) } }];

const raw = $input.first().json;
const d = raw.body || raw;

const workflowName = d.workflowName || d.workflow_name || d.name || 'Unknown Workflow';
const status       = d.status || 'Completed';
const nodesRun     = d.nodesExecuted ?? d.nodes_executed ?? null;
const duration     = d.duration ?? null;
const execUrl      = d.executionUrl  || d.execution_url  || null;
const notes        = d.notes || null;

const fields = [
  { name: '📋 Workflow', value: workflowName, inline: true },
  { name: '✅ Status',   value: status,       inline: true }
];
if (nodesRun !== null) fields.push({ name: '⚡ Nodes Run',  value: String(nodesRun), inline: true });
if (duration  !== null) fields.push({ name: '⏱️ Duration', value: String(duration), inline: true });
if (execUrl)  fields.push({ name: '🔗 Execution', value: '[View in n8n](' + execUrl + ')', inline: false });
if (notes)    fields.push({ name: '📝 Notes',     value: notes, inline: false });

const payload = {
  embeds: [{
    title: '✅ Workflow Completed',
    color: 5763719,
    fields,
    timestamp: new Date().toISOString(),
    footer: { text: 'Thurnos Prime • Thurr Solutions Ops' }
  }]
};

return [{ json: { payload: JSON.stringify(payload) } }];
